import React, { useEffect, useState } from "react";
import EditorShell from "./shared/EditorShell";
import BaseQuestionFields from "./shared/BaseQuestionFields";
import FAWCheckbox from "../../../../component-widget/FAWCheckbox";

export default function QuePSACompanyEditor({ data, onSave, onClose, saveRef, isDefaultLanguage = true }) {
  const [item, setItem] = useState(
    data || { name: "", text: "", required: false, validationMessage: "", horizontalLine: false, isHidden: false, notes: false }
  );
  useEffect(()=>{ if (data) setItem(prev=>({ ...prev, ...data })); }, [data]);
  const handleSave = () => { 
    onSave?.(item); 

  };
  return (
    <EditorShell onSave={handleSave} onClose={onClose} saveRef={saveRef}>
      <BaseQuestionFields 
        item={item} 
        onChange={setItem} 
        isDefaultLanguage={isDefaultLanguage} 
        suppressValidation={true}
        questionType="PSACompany"
      />
      <div style={{ display: "flex", flexDirection: "column", gap: 16, marginTop: 16 }}>
        <FAWCheckbox 
          label="Bold in PDF"
          checked={!!item.notes} 
          onChange={(e)=> setItem(prev=>({ ...prev, notes: e.target.checked }))}
          labelStyle={{ fontSize: '12px' }}
        />
        <FAWCheckbox 
          label="Hide in PDF"
          checked={!!item.isHidden} 
          onChange={(e)=> setItem(prev=>({ ...prev, isHidden: e.target.checked }))}
          labelStyle={{ fontSize: '12px' }}
        />
      </div>
    </EditorShell>
  );
}



